const data = $input.first().json;
const sessionKey = `reserva_${data.sessionId}`;
let partial = {};
try {
  const stored = $vars[sessionKey];
  if (stored) partial = JSON.parse(stored);
} catch(e) {}

const collected = Object.entries(partial).map(([k, v]) => `${k}: ${v}`).join(', ') || 'nada aun';

const reservaPrompt = `${data.systemPrompt}

MODO RESERVA ACTIVO
Datos recopilados: ${collected}

Tu tarea: recopilar los datos faltantes en este orden:
1. Fecha (no pasada, maximo 30 dias en el futuro, formato YYYY-MM-DD)
2. Hora (slots disponibles: 12:00, 13:00, 19:00, 20:00, 21:00)
3. Numero de personas (minimo 1, maximo 10)
4. Nombre del cliente
5. Telefono de contacto

Cuando tengas TODOS los datos, muestra un resumen y pregunta Confirmo tu reserva?
Si el cliente confirma, termina con la linea exacta:
RESERVATION_CONFIRMED|fecha|hora|personas|nombre|telefono
Ejemplo: RESERVATION_CONFIRMED|2026-04-26|19:00|4|Juan Garcia|999888777`;

return [{ json: { ...data, reservaPrompt, partial, sessionKey } }];

const responseText = $input.first().json.content?.[0]?.text ?? '';
const confirmMatch = responseText.match(/RESERVATION_CONFIRMED\|([^|]+)\|([^|]+)\|(\d+)\|([^|]+)\|([^\n]+)/);
const confirmed = !!confirmMatch;
const cleanText = responseText.replace(/RESERVATION_CONFIRMED\|.*/, '').trim();
const prev = $('Build Reservation Prompt').first().json;

return [{ json: {
  ...prev,
  botResponse: cleanText,
  reservationConfirmed: confirmed,
  reservationData: confirmed ? {
    date: confirmMatch[1].trim(),
    time: confirmMatch[2].trim(),
    party_size: parseInt(confirmMatch[3]),
    customer_name: confirmMatch[4].trim(),
    customer_phone: confirmMatch[5].trim(),
  } : null,
} }];

const reservaId = $input.first().json.id ?? 'nueva';
const prev = $('Parse Reservation').first().json;
const rd = prev.reservationData;
return [{ json: { ...prev, botResponse: `Reserva #${String(reservaId).slice(0,8)} confirmada\nFecha: ${rd.date} a las ${rd.time} para ${rd.party_size} personas. Te esperamos, ${rd.customer_name}!` } }];
